</head>
<body>

<canvas id="canvas"></canvas>

<div class="cursor-ring" id="cursorRing"></div>
<div class="cursor-dot" id="cursorDot"></div>

<div class="title">
  <h1>VORTEX</h1>
  <p>Move to create &middot; Click to explode</p>
</div>

<div class="stats">
  <span id="particleCount">0</span>
  <label>Particles</label>
</div>

<div class="mode-label" id="modeLabel">VORTEX</div>

<div class="controls">
  <button class="control-btn active" data-mode="vortex">Vortex</button>
  <button class="control-btn" data-mode="gravity">Gravity</button>
  <button class="control-btn" data-mode="repel">Repel</button>
  <button class="control-btn" data-mode="chaos">Chaos</button>
</div>

<script>
const canvas = document.getElementById('canvas');
const ctx = canvas.getContext('2d');
const cursorRing = document.getElementById('cursorRing');
const cursorDot = document.getElementById('cursorDot');
const particleCountEl = document.getElementById('particleCount');
const modeLabel = document.getElementById('modeLabel');

let W, H;
let mouse = { x: -1000, y: -1000, px: -1000, py: -1000 };
let mouseDown = false;
let currentMode = 'vortex';
let particles = [];
let trails = [];
let time = 0;
let ringX = -1000, ringY = -1000;

const MAX_PARTICLES = 2500;
const TRAIL_LENGTH = 8;

const PALETTES = {
  vortex: [
    [255, 60, 100],
    [255, 120, 50],
    [255, 200, 0],
    [255, 80, 180],
    [200, 50, 255],
  ],
  gravity: [
    [0, 200, 255],
    [0, 255, 200],
    [100, 120, 255],
    [0, 180, 180],
    [50, 255, 150],
  ],
  repel: [
    [255, 255, 100],
    [255, 200, 0],
    [255, 150, 50],
    [255, 100, 0],
    [255, 80, 80],
  ],
  chaos: [
    [255, 0, 100],
    [0, 255, 200],
    [255, 200, 0],
    [150, 50, 255],
    [0, 200, 255],
  ]
};

function resize() {
  W = canvas.width = window.innerWidth;
  H = canvas.height = window.innerHeight;
}
resize();
window.addEventListener('resize', resize);

class Particle {
  constructor(x, y, vx, vy, palette) {
    this.x = x;
    this.y = y;
    this.vx = vx || (Math.random() - 0.5) * 4;
    this.vy = vy || (Math.random() - 0.5) * 4;
    this.life = 1;
    this.decay = 0.002 + Math.random() * 0.004;
    this.size = 1.5 + Math.random() * 3;
    const pal = palette || PALETTES[currentMode];
    const col = pal[Math.floor(Math.random() * pal.length)];
    this.r = col[0];
    this.g = col[1];
    this.b = col[2];
    this.trail = [];
  }

  update() {
    const dx = mouse.x - this.x;
    const dy = mouse.y - this.y;
    const dist = Math.sqrt(dx * dx + dy * dy) || 1;
    const force = Math.min(800 / (dist * dist), 2);
    const angle = Math.atan2(dy, dx);

    switch (currentMode) {
      case 'vortex': {
        const perpAngle = angle + Math.PI * 0.5;
        this.vx += (Math.cos(perpAngle) * force * 1.5 + Math.cos(angle) * force * 0.3);
        this.vy += (Math.sin(perpAngle) * force * 1.5 + Math.sin(angle) * force * 0.3);
        break;
      }
      case 'gravity': {
        this.vx += Math.cos(angle) * force * 1.8;
        this.vy += Math.sin(angle) * force * 1.8;
        break;
      }
      case 'repel': {
        this.vx -= Math.cos(angle) * force * 2;
        this.vy -= Math.sin(angle) * force * 2;
        break;
      }
      case 'chaos': {
        const t = time * 0.01;
        const noiseAngle = Math.sin(this.x * 0.005 + t) * Math.cos(this.y * 0.005 + t) * Math.PI * 2;
        this.vx += Math.cos(noiseAngle) * 0.3 + Math.cos(angle) * force * 0.5;
        this.vy += Math.sin(noiseAngle) * 0.3 + Math.sin(angle) * force * 0.5;
        break;
      }
    }

    this.vx *= 0.97;
    this.vy *= 0.97;

    this.trail.push({ x: this.x, y: this.y });
    if (this.trail.length > TRAIL_LENGTH) this.trail.shift();

    this.x += this.vx;
    this.y += this.vy;
    this.life -= this.decay;

    if (mouseDown) {
      this.life -= 0.002;
      const speed = Math.sqrt(this.vx * this.vx + this.vy * this.vy);
      if (speed < 8) {
        this.vx *= 1.05;
        this.vy *= 1.05;
      }
    }
  }

  draw() {
    const alpha = this.life * 0.6;

    // Trail
    if (this.trail.length > 1) {
      ctx.beginPath();
      ctx.moveTo(this.trail[0].x, this.trail[0].y);
      for (let i = 1; i < this.trail.length; i++) {
        ctx.lineTo(this.trail[i].x, this.trail[i].y);
      }
      ctx.lineTo(this.x, this.y);
      ctx.strokeStyle = `rgba(${this.r},${this.g},${this.b},${alpha * 0.3})`;
      ctx.lineWidth = this.size * 0.5;
      ctx.stroke();
    }

    // Glow
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.size * 2, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(${this.r},${this.g},${this.b},${alpha * 0.15})`;
    ctx.fill();

    // Core
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(${this.r},${this.g},${this.b},${alpha})`;
    ctx.fill();

    // Hot center
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.size * 0.4, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(255,255,255,${alpha * 0.6})`;
    ctx.fill();
  }
}

function spawnParticles(x, y, count, spread, speedMult) {
  for (let i = 0; i < count; i++) {
    if (particles.length >= MAX_PARTICLES) break;
    const angle = Math.random() * Math.PI * 2;
    const sp = Math.random() * (spread || 3) * (speedMult || 1);
    particles.push(new Particle(
      x + (Math.random() - 0.5) * 10,
      y + (Math.random() - 0.5) * 10,
      Math.cos(angle) * sp,
      Math.sin(angle) * sp
    ));
  }
}

function explode(x, y) {
  const count = 120;
  for (let i = 0; i < count; i++) {
    if (particles.length >= MAX_PARTICLES) break;
    const angle = (i / count) * Math.PI * 2 + Math.random() * 0.3;
    const speed = 3 + Math.random() * 12;
    const p = new Particle(x, y, Math.cos(angle) * speed, Math.sin(angle) * speed);
    p.size = 2 + Math.random() * 4;
    p.decay = 0.005 + Math.random() * 0.008;
    particles.push(p);
  }
}

// Mouse tracking
document.addEventListener('mousemove', (e) => {
  mouse.px = mouse.x;
  mouse.py = mouse.y;
  mouse.x = e.clientX;
  mouse.y = e.clientY;

  const speed = Math.sqrt((mouse.x - mouse.px) ** 2 + (mouse.y - mouse.py) ** 2);
  const count = Math.min(Math.floor(speed * 0.3), 8);
  if (count > 0) spawnParticles(mouse.x, mouse.y, count, 2, 0.5);
});

document.addEventListener('mousedown', (e) => {
  mouseDown = true;
  explode(e.clientX, e.clientY);
  cursorRing.style.width = '60px';
  cursorRing.style.height = '60px';
  cursorRing.style.borderColor = 'rgba(255, 200, 0, 0.9)';
});

document.addEventListener('mouseup', () => {
  mouseDown = false;
  cursorRing.style.width = '40px';
  cursorRing.style.height = '40px';
  cursorRing.style.borderColor = 'rgba(255, 60, 100, 0.8)';
});

// Touch support
document.addEventListener('touchstart', (e) => {
  const t = e.touches[0];
  mouse.x = t.clientX;
  mouse.y = t.clientY;
  mouseDown = true;
  explode(t.clientX, t.clientY);
});

document.addEventListener('touchmove', (e) => {
  e.preventDefault();
  const t = e.touches[0];
  mouse.px = mouse.x;
  mouse.py = mouse.y;
  mouse.x = t.clientX;
  mouse.y = t.clientY;
  const speed = Math.sqrt((mouse.x - mouse.px) ** 2 + (mouse.y - mouse.py) ** 2);
  spawnParticles(mouse.x, mouse.y, Math.min(Math.floor(speed * 0.3), 8), 2, 0.5);
}, { passive: false });

document.addEventListener('touchend', () => { mouseDown = false; });

// Controls
document.querySelectorAll('.control-btn').forEach(btn => {
  btn.addEventListener('click', () => {
    document.querySelectorAll('.control-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    currentMode = btn.dataset.mode;
    modeLabel.textContent = currentMode.toUpperCase();
    modeLabel.classList.add('visible');
    setTimeout(() => modeLabel.classList.remove('visible'), 1500);
  });
});

// Ambient spawner
function ambientSpawn() {
  if (particles.length < 200) {
    const edge = Math.floor(Math.random() * 4);
    let x, y;
    switch(edge) {
      case 0: x = Math.random() * W; y = -10; break;
      case 1: x = W + 10; y = Math.random() * H; break;
      case 2: x = Math.random() * W; y = H + 10; break;
      case 3: x = -10; y = Math.random() * H; break;
    }
    spawnParticles(x, y, 2, 1, 0.3);
  }
}

// Cursor smoothing
function updateCursor() {
  ringX += (mouse.x - ringX) * 0.12;
  ringY += (mouse.y - ringY) * 0.12;
  cursorRing.style.left = ringX + 'px';
  cursorRing.style.top = ringY + 'px';
  cursorDot.style.left = mouse.x + 'px';
  cursorDot.style.top = mouse.y + 'px';
}

function animate() {
  time++;

  // Fade effect
  ctx.fillStyle = 'rgba(10, 10, 10, 0.12)';
  ctx.fillRect(0, 0, W, H);

  // Subtle background pulse
  if (time % 3 === 0) ambientSpawn();

  // Mouse glow
  if (mouse.x > 0) {
    const gradient = ctx.createRadialGradient(mouse.x, mouse.y, 0, mouse.x, mouse.y, 200);
    const pal = PALETTES[currentMode][0];
    gradient.addColorStop(0, `rgba(${pal[0]},${pal[1]},${pal[2]},${mouseDown ? 0.06 : 0.03})`);
    gradient.addColorStop(1, 'rgba(10,10,10,0)');
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, W, H);
  }

  // Continuous spawn while holding
  if (mouseDown && time % 2 === 0) {
    spawnParticles(mouse.x + (Math.random()-0.5)*40, mouse.y + (Math.random()-0.5)*40, 5, 6, 1.5);
  }

  // Update & draw particles
  for (let i = particles.length - 1; i >= 0; i--) {
    particles[i].update();
    particles[i].draw();
    if (particles[i].life <= 0 ||
        particles[i].x < -100 || particles[i].x > W + 100 ||
        particles[i].y < -100 || particles[i].y > H + 100) {
      particles.splice(i, 1);
    }
  }

  // Update counter
  if (time % 10 === 0) {
    particleCountEl.textContent = particles.length;
  }

  updateCursor();
  requestAnimationFrame(animate);
}

animate();

// Keyboard shortcuts
document.addEventListener('keydown', (e) => {
  const modes = ['vortex', 'gravity', 'repel', 'chaos'];
  const idx = parseInt(e.key) - 1;
  if (idx >= 0 && idx < modes.length) {
    document.querySelectorAll('.control-btn').forEach(b => b.classList.remove('active'));
    document.querySelector(`[data-mode="${modes[idx]}"]`).classList.add('active');
    currentMode = modes[idx];
    modeLabel.textContent = currentMode.toUpperCase();
    modeLabel.classList.add('visible');
    setTimeout(() => modeLabel.classList.remove('visible'), 1500);
  }
  if (e.key === ' ') {
    e.preventDefault();
    explode(W/2, H/2);
  }
});
</script>

</body>
</html>
