function RoseChart({ data, color, glow, compareData, compareColor, compareGlow, size }) {
  const svgRef = useRef(null);
  const prevDataRef = useRef(data);
  const prevCompareRef = useRef(compareData);

  useEffect(() => {
    if (!svgRef.current) return;
    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const cx = size / 2;
    const cy = size / 2;
    const maxR = size * 0.38;
    const n = COMPETENCIES.length;
    const angleSlice = (Math.PI * 2) / n;

    const g = svg.append("g").attr("transform", `translate(${cx},${cy})`);

    // Grid rings
    const rings = [2, 4, 6, 8, 10];
    rings.forEach((r) => {
      const radius = (r / 10) * maxR;
      g.append("circle")
        .attr("r", radius)
        .attr("fill", "none")
        .attr("stroke", "rgba(255,255,255,0.06)")
        .attr("stroke-width", r === 10 ? 1.5 : 0.5);
    });

    // Axis lines & labels
    COMPETENCIES.forEach((comp, i) => {
      const angle = angleSlice * i - Math.PI / 2;
      const x2 = Math.cos(angle) * maxR;
      const y2 = Math.sin(angle) * maxR;

      g.append("line")
        .attr("x1", 0).attr("y1", 0)
        .attr("x2", x2).attr("y2", y2)
        .attr("stroke", "rgba(255,255,255,0.08)")
        .attr("stroke-width", 0.5);

      const labelR = maxR + 18;
      const lx = Math.cos(angle) * labelR;
      const ly = Math.sin(angle) * labelR;

      const text = g.append("text")
        .attr("x", lx).attr("y", ly)
        .attr("text-anchor", "middle")
        .attr("dominant-baseline", "middle")
        .attr("fill", "rgba(255,255,255,0.45)")
        .attr("font-size", size < 500 ? "9px" : "10.5px")
        .attr("font-family", "'DM Sans', sans-serif")
        .attr("font-weight", 400)
        .attr("letter-spacing", "0.02em");

      // Word wrap long labels
      const words = comp.split(" ");
      if (words.length <= 2) {
        text.text(comp);
      } else {
        const mid = Math.ceil(words.length / 2);
        text.append("tspan").attr("x", lx).attr("dy", "-0.4em").text(words.slice(0, mid).join(" "));
        text.append("tspan").attr("x", lx).attr("dy", "1.15em").text(words.slice(mid).join(" "));
      }
    });

    // Rose petal path generator
    const rosePath = (values, smooth = true) => {
      const points = values.map((v, i) => {
        const angle = angleSlice * i - Math.PI / 2;
        const r = (v / 10) * maxR;
        return [Math.cos(angle) * r, Math.sin(angle) * r];
      });
      points.push(points[0]);

      if (!smooth) {
        return "M" + points.map((p) => p.join(",")).join("L") + "Z";
      }

      let path = `M${points[0][0]},${points[0][1]}`;
      for (let i = 0; i < points.length - 1; i++) {
        const curr = points[i];
        const next = points[(i + 1) % points.length];
        const cpx = (curr[0] + next[0]) / 2;
        const cpy = (curr[1] + next[1]) / 2;
        path += `Q${curr[0]},${curr[1]} ${cpx},${cpy}`;
      }
      path += "Z";
      return path;
    };

    // Animated interpolation
    const animatePath = (selection, fromData, toData, pathColor, pathGlow, opacity) => {
      const fromValues = fromData || toData.map(() => 0);
      selection
        .attr("d", rosePath(fromValues))
        .transition()
        .duration(800)
        .ease(d3.easeCubicOut)
        .attrTween("d", () => {
          const interp = fromValues.map((from, i) => d3.interpolate(from, toData[i]));
          return (t) => rosePath(interp.map((fn) => fn(t)));
        });
    };

    // Compare shape (if exists)
    if (compareData) {
      const compareGlowFilter = g.append("defs").append("filter").attr("id", "compareGlow");
      compareGlowFilter.append("feGaussianBlur").attr("stdDeviation", "6").attr("result", "blur");
      compareGlowFilter.append("feComposite").attr("in", "SourceGraphic").attr("in2", "blur");

      const compareShape = g.append("path")
        .attr("fill", compareColor)
        .attr("fill-opacity", 0.08)
        .attr("stroke", compareColor)
        .attr("stroke-width", 1.5)
        .attr("stroke-opacity", 0.5)
        .attr("filter", "url(#compareGlow)")
        .style("stroke-dasharray", "6,4");

      animatePath(compareShape, prevCompareRef.current, compareData, compareColor, compareGlow, 0.08);

      // Compare dots
      compareData.forEach((v, i) => {
        const angle = angleSlice * i - Math.PI / 2;
        const r = (v / 10) * maxR;
        g.append("circle")
          .attr("cx", Math.cos(angle) * r)
          .attr("cy", Math.sin(angle) * r)
          .attr("r", 3)
          .attr("fill", compareColor)
          .attr("fill-opacity", 0)
          .transition()
          .delay(400 + i * 40)
          .duration(400)
          .attr("fill-opacity", 0.7);
      });
    }

    // Glow filter
    const glowFilter = g.append("defs").append("filter").attr("id", "mainGlow");
    glowFilter.append("feGaussianBlur").attr("stdDeviation", "8").attr("result", "blur");
    glowFilter.append("feComposite").attr("in", "SourceGraphic").attr("in2", "blur");

    // Main glow layer
    const glowShape = g.append("path")
      .attr("fill", color)
      .attr("fill-opacity", 0.12)
      .attr("stroke", "none")
      .attr("filter", "url(#mainGlow)");
    animatePath(glowShape, prevDataRef.current, data, color, glow, 0.15);

    // Main shape
    const mainShape = g.append("path")
      .attr("fill", color)
      .attr("fill-opacity", 0.15)
      .attr("stroke", color)
      .attr("stroke-width", 2)
      .attr("stroke-opacity", 0.9);
    animatePath(mainShape, prevDataRef.current, data, color, glow, 0.15);

    // Vertex dots
    data.forEach((v, i) => {
      const angle = angleSlice * i - Math.PI / 2;
      const r = (v / 10) * maxR;

      // Outer glow dot
      g.append("circle")
        .attr("cx", Math.cos(angle) * r)
        .attr("cy", Math.sin(angle) * r)
        .attr("r", 6)
        .attr("fill", color)
        .attr("fill-opacity", 0)
        .transition()
        .delay(400 + i * 50)
        .duration(400)
        .attr("fill-opacity", 0.25);

      // Core dot
      g.append("circle")
        .attr("cx", Math.cos(angle) * r)
        .attr("cy", Math.sin(angle) * r)
        .attr("r", 3.5)
        .attr("fill", color)
        .attr("fill-opacity", 0)
        .transition()
        .delay(400 + i * 50)
        .duration(400)
        .attr("fill-opacity", 1);

      // White center
      g.append("circle")
        .attr("cx", Math.cos(angle) * r)
        .attr("cy", Math.sin(angle) * r)
        .attr("r", 1.5)
        .attr("fill", "#fff")
        .attr("fill-opacity", 0)
        .transition()
        .delay(500 + i * 50)
        .duration(300)
        .attr("fill-opacity", 0.8);
    });

    // Score labels at vertices
    data.forEach((v, i) => {
      const angle = angleSlice * i - Math.PI / 2;
      const r = (v / 10) * maxR + 10;
      if (v > 0) {
        g.append("text")
          .attr("x", Math.cos(angle) * r)
          .attr("y", Math.sin(angle) * r)
          .attr("text-anchor", "middle")
          .attr("dominant-baseline", "middle")
          .attr("fill", color)
          .attr("font-size", "10px")
          .attr("font-family", "'DM Sans', sans-serif")
          .attr("font-weight", 700)
          .attr("opacity", 0)
          .text(v)
          .transition()
          .delay(600 + i * 50)
          .duration(400)
          .attr("opacity", 0.8);
      }
    });

    prevDataRef.current = data;
    prevCompareRef.current = compareData;
  }, [data, color, glow, compareData, compareColor, compareGlow, size]);

  return <svg ref={svgRef} width={size} height={size} />;
}

export default function DesignerCompass() {
  const [archetype, setArchetype] = useState("storyteller");
  const [level, setLevel] = useState("senior");
  const [compareArchetype, setCompareArchetype] = useState(null);
  const [chartSize, setChartSize] = useState(520);
  const containerRef = useRef(null);

  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current) {
        const w = containerRef.current.offsetWidth;
        setChartSize(Math.min(Math.max(w * 0.7, 340), 560));
      }
    };
    handleResize();
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const currentData = DATA[archetype][level];
  const compareData = compareArchetype ? DATA[compareArchetype][level] : null;
  const arc = ARCHETYPES[archetype];
  const cmpArc = compareArchetype ? ARCHETYPES[compareArchetype] : null;

  const topCompetencies = useMemo(() => {
    return currentData
      .map((v, i) => ({ name: COMPETENCIES[i], value: v }))
      .sort((a, b) => b.value - a.value)
      .slice(0, 3);
  }, [currentData]);

  return (
    <div style={{
      minHeight: "100vh",
      background: "#0B0B0F",
      fontFamily: "'DM Sans', sans-serif",
      color: "#fff",
      position: "relative",
      overflow: "hidden",
    }}>
      <link href="https://fonts.googleapis.com/css2?family=DM+Sans:ital,opsz,wght@0,9..40,200;0,9..40,400;0,9..40,500;0,9..40,700;1,9..40,200&family=Syne:wght@700;800&display=swap" rel="stylesheet" />

      {/* Ambient background glow */}
      <div style={{
        position: "fixed", top: "-30%", left: "-10%",
        width: "60%", height: "60%", borderRadius: "50%",
        background: `radial-gradient(circle, ${arc.glow} 0%, transparent 70%)`,
        filter: "blur(80px)", pointerEvents: "none",
        transition: "background 0.8s ease",
      }} />
      <div style={{
        position: "fixed", bottom: "-20%", right: "-10%",
        width: "50%", height: "50%", borderRadius: "50%",
        background: `radial-gradient(circle, ${cmpArc?.glow || "rgba(255,255,255,0.02)"} 0%, transparent 70%)`,
        filter: "blur(80px)", pointerEvents: "none",
        transition: "background 0.8s ease",
      }} />

      {/* Grain overlay */}
      <div style={{
        position: "fixed", inset: 0, pointerEvents: "none", opacity: 0.03, zIndex: 100,
        backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E")`,
      }} />

      <div style={{ position: "relative", zIndex: 10, maxWidth: 1100, margin: "0 auto", padding: "40px 24px 60px" }}>

        {/* Header */}
        <div style={{ marginBottom: 40 }}>
          <h1 style={{
            fontFamily: "'Syne', sans-serif", fontWeight: 800,
            fontSize: "clamp(1.8rem, 4vw, 2.8rem)",
            letterSpacing: "-0.02em", lineHeight: 1,
            background: `linear-gradient(135deg, ${arc.color}, #fff)`,
            WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
            transition: "all 0.6s ease", marginBottom: 6,
          }}>
            Competency Radar
          </h1>
          <p style={{ color: "rgba(255,255,255,0.35)", fontSize: 13, letterSpacing: "0.15em", fontWeight: 200, textTransform: "uppercase" }}>
            Designer Archetype × Career Level
          </p>
        </div>

        <div style={{ display: "flex", gap: 40, flexWrap: "wrap" }}>

          {/* Left: Controls */}
          <div style={{ flex: "0 0 280px", minWidth: 240 }}>
            {/* Archetype selection */}
            <div style={{ marginBottom: 28 }}>
              <label style={{ display: "block", fontSize: 10, letterSpacing: "0.2em", textTransform: "uppercase", color: "rgba(255,255,255,0.3)", marginBottom: 10, fontWeight: 500 }}>
