                  <button
                    key={key}
                    onClick={() => { setArchetype(key); if (compareArchetype === key) setCompareArchetype(null); }}
                    style={{
                      background: archetype === key ? `${a.color}12` : "transparent",
                      border: `1px solid ${archetype === key ? a.color + "60" : "rgba(255,255,255,0.06)"}`,
