                    <span style={{ fontSize: 10, color: compareArchetype === key ? "#fff" : "rgba(255,255,255,0.35)" }}>
                      {a.name.split(" ")[0]}
                    </span>
                  </button>
                ))}
              </div>
            </div>

            {/* Top competencies */}
            <div style={{
              background: "rgba(255,255,255,0.02)",
              border: "1px solid rgba(255,255,255,0.06)",
              borderRadius: 10, padding: 16,
            }}>
              <label style={{ display: "block", fontSize: 10, letterSpacing: "0.2em", textTransform: "uppercase", color: "rgba(255,255,255,0.3)", marginBottom: 12, fontWeight: 500 }}>
                Peak Strengths
              </label>
              {topCompetencies.map((c, i) => (
                <div key={c.name} style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: i < 2 ? 10 : 0 }}>
                  <span style={{ fontFamily: "'Syne', sans-serif", fontSize: 22, fontWeight: 800, color: arc.color, minWidth: 30, transition: "color 0.6s" }}>
