                  </span>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: 12, fontWeight: 500, color: "rgba(255,255,255,0.7)" }}>{c.name}</div>
                    <div style={{
                      marginTop: 4, height: 3, borderRadius: 2,
                      background: "rgba(255,255,255,0.06)",
                      overflow: "hidden",
                    }}>
                      <div style={{
                        height: "100%", borderRadius: 2,
                        width: `${c.value * 10}%`,
                        background: `linear-gradient(90deg, ${arc.color}, ${arc.color}88)`,
                        transition: "all 0.8s cubic-bezier(0.16,1,0.3,1)",
                      }} />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Right: Chart */}
          <div ref={containerRef} style={{ flex: 1, minWidth: 300, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" }}>
            {/* Legend */}
            <div style={{ display: "flex", gap: 24, marginBottom: 16, flexWrap: "wrap", justifyContent: "center" }}>
              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <div style={{ width: 20, height: 3, borderRadius: 2, background: arc.color, transition: "background 0.6s" }} />
                <span style={{ fontSize: 11, color: "rgba(255,255,255,0.5)" }}>{arc.name}</span>
              </div>
              {cmpArc && (
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <div style={{ width: 20, height: 3, borderRadius: 2, background: cmpArc.color, opacity: 0.6, borderTop: `1px dashed ${cmpArc.color}` }} />
                  <span style={{ fontSize: 11, color: "rgba(255,255,255,0.5)" }}>{cmpArc.name}</span>
                </div>
              )}
            </div>

            <RoseChart
              data={currentData}
              color={arc.color}
              glow={arc.glow}
              compareData={compareData}
              compareColor={cmpArc?.color}
              compareGlow={cmpArc?.glow}
              size={chartSize}
            />

            <p style={{ fontSize: 11, color: "rgba(255,255,255,0.2)", marginTop: 12, textAlign: "center", fontStyle: "italic", maxWidth: 380 }}>
              Scores represent relative competency emphasis — not absolute skill. Every archetype needs all ten; the shape shows where each one leads.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

